   917→  content: string | Array<{ type: string; [key: string]: unknown }>;
   918→};
   919→
   920→type CompletionOptions = {
   921→  temperature?: number;
   922→  max_tokens?: number;
   923→  top_p?: number;
   924→  stop?: string[];
   925→  response_format?: { type: string };
   926→};
   927→
   928→export async function chatCompletion(
   929→  messages: ChatMessage[],
   930→  options: CompletionOptions = {}
   931→): Promise<string> {
   932→  const res = await fetch(AI_ENDPOINT, {
   933→    method: "POST",
   934→    headers: { "Content-Type": "application/json", Accept: "application/json" },
   935→    body: JSON.stringify({ model: AI_MODEL, messages, ...options }),
   936→  });
   937→  if (!res.ok) {
   938→    const body = await res.text();
   939→    throw new Error(`AI API ${res.status}: ${body}`);
   940→  }
   941→  const data = await res.json();
   942→  return data.choices[0].message.content;
   943→}
   944→
   945→export async function safeJsonCompletion<T = unknown>(
   946→  messages: ChatMessage[],
   947→  options: CompletionOptions = {}
   948→): Promise<T> {
   949→  const raw = await chatCompletion(messages, options);
   950→  const match = raw.match(/\{[\s\S]*\}|\[[\s\S]*\]/);
   951→  if (!match) throw new Error(`Expected JSON but got: ${raw.slice(0, 200)}`);
   952→  return JSON.parse(match[0]);
   953→}
   954→
   955→export async function withRetry<T>(fn: () => Promise<T>, maxAttempts = 3): Promise<T> {
   956→  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
   957→    try {
   958→      return await fn();
   959→    } catch (err) {
   960→      if (attempt === maxAttempts) throw err;
   961→      await new Promise((r) => setTimeout(r, 1000 * attempt));
   962→    }
   963→  }
   964→  throw new Error("unreachable");
   965→}
