   972→    reader.onload = () => resolve(reader.result as string);
   973→    reader.onerror = () => reject(new Error("Failed to read file"));
   974→    reader.readAsDataURL(file);
   975→  });
   976→}
   977→
   978→export async function urlToDataUri(url: string): Promise<string> {
   979→  const res = await fetch(url);
   980→  const blob = await res.blob();
